function close(actual, expected, tolerance = 1e-12, label = "value") {
  assert.ok(
    Math.abs(actual - expected) <= tolerance,
    `${label}: expected ${expected}, received ${actual}, delta ${Math.abs(actual - expected)}`,
  );
}

